class Solution {
public:
    int nextGreaterElement(int n) {
        string a = to_string(n);
        int i = (int)a.size()-2;
        while (i>=0 && a[i]>=a[i+1]) i--;
        if (i<0) return -1;
        int j = (int)a.size()-1;
        while (a[j]<=a[i]) j--;
        swap(a[i], a[j]);
        reverse(a.begin()+i+1, a.end());
        long long ans = stoll(a);
        return ans >= (1LL<<31) ? -1 : (int)ans;
    }
};
